SELECT ?year WHERE {
  ?item wdt:P31 wd:Q18397;
        wdt:P1325 ?date.
  FILTER (regex(str(?date), "-04-01"))
  BIND(year(?date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 1

